sql:
SELECT SUM(value) AS total_predictor_values
FROM predictor_values
WHERE user_id = 1 AND predictor_id = 2;

SELECT model_id, AVG(predictive_coefficient) AS average_predictive_coefficient
FROM user_models
GROUP BY model_id;

SELECT user_id, predictor_id, value
FROM predictor_values
WHERE predictor_id = 1;

SELECT user_id, predictor_id, MIN(value) AS Min_Predictor_Value, MAX(value) AS Max_Predictor_Value, AVG(value) AS Average_Predictor_Value
FROM predictor_values
GROUP BY user_id, predictor_id;

SELECT predictor_id 
FROM predictor_values 
WHERE predictor_id NOT IN (
    SELECT predictor_id 
    FROM outcome_rsd
);

SELECT up.user_id, COUNT(DISTINCT up.predictor_id) AS unique_predictor_count
FROM user_predictors up
GROUP BY up.user_id;

SELECT users.user_id, users.user_name
FROM users
INNER JOIN predictor_values ON users.user_id = predictor_values.user_id;

SELECT COUNT(*) 
FROM user_predictors 
WHERE user_id = 1;

SELECT predictor_id, COUNT(DISTINCT user_id) 
FROM predictor_values 
GROUP BY predictor_id;

SELECT COUNT(DISTINCT user_id)
FROM predictor_values
WHERE predictor_id = (SELECT predictor_id FROM predictors WHERE predictor_name = 'Fitbit Active Score');

SELECT AVG(value) AS average_predictor_value
FROM predictor_values
WHERE user_id = 1;

SELECT app_type, COUNT(DISTINCT user_id) AS user_count
FROM app_data
GROUP BY app_type;

SELECT user_id, COUNT(predictor_id) AS num_predictors
FROM user_predictors
GROUP BY user_id;
